import os
import json
import base64
from datetime import datetime, timezone

from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1


storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

PROJECT_ID = os.environ.get("GCP_PROJECT") or os.environ.get("GOOGLE_CLOUD_PROJECT")
PUBSUB_TOPIC = os.environ.get("PUBSUB_TOPIC", "")
FIRESTORE_COLLECTION = os.environ.get("FIRESTORE_COLLECTION", "processed_files")


def process_gcs_file(event, context):
    bucket_name = event.get("bucket")
    file_name = event.get("name")
    generation = event.get("generation")
    content_type = event.get("contentType")
    metageneration = event.get("metageneration")

    if not bucket_name or not file_name:
        return "Missing bucket or file name"

    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)

    try:
        file_bytes = blob.download_as_bytes()
        file_text = file_bytes.decode("utf-8", errors="replace")
    except Exception as exc:
        file_text = ""
        error_message = str(exc)
    else:
        error_message = None

    doc_id = f"{bucket_name}:{file_name}:{generation or 'unknown'}"
    doc_ref = firestore_client.collection(FIRESTORE_COLLECTION).document(doc_id)

    record = {
        "bucket": bucket_name,
        "name": file_name,
        "generation": generation,
        "metageneration": metageneration,
        "content_type": content_type,
        "size": len(file_bytes) if "file_bytes" in locals() else None,
        "processed_at": datetime.now(timezone.utc).isoformat(),
        "text_preview": file_text[:1000],
        "error": error_message,
        "event_id": getattr(context, "event_id", None),
        "event_type": getattr(context, "event_type", None),
    }

    doc_ref.set(record)

    if PUBSUB_TOPIC:
        topic_path = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)
        message = {
            "bucket": bucket_name,
            "name": file_name,
            "generation": generation,
            "doc_id": doc_id,
            "processed_at": record["processed_at"],
            "error": error_message,
        }
        publisher.publish(topic_path, json.dumps(message).encode("utf-8"))

    return "OK"


